class Solution:
    def maxNumberOfAlloys(self, n, k, budget, composition, stock, cost):
        best = 0
        for i in range(k):
            comp = composition[i]
            x = 0
            while True:
                nxt = x + 1
                total = 0
                for j in range(n):
                    need = comp[j] * nxt - stock[j]
                    if need > 0:
                        total += need * cost[j]
                if total <= budget:
                    x = nxt
                else:
                    break
            if x > best:
                best = x
        return best

