class Solution:
    def maxNumberOfAlloys(self, n, k, budget, composition, stock, cost):
        best = 0
        hi_bound = budget + max(stock) + 2
        for i in range(k):
            comp = composition[i]
            def feasible(x):
                total = 0
                for j in range(n):
                    need = comp[j] * x - stock[j]
                    if need > 0:
                        total += need * cost[j]
                        if total > budget:
                            return False
                return True
            lo, hi = 0, hi_bound
            while lo < hi:
                mid = (lo + hi + 1) // 2
                if feasible(mid):
                    lo = mid
                else:
                    hi = mid - 1
            if lo > best:
                best = lo
        return best

