var maxNumberOfAlloys = function(n, k, budget, composition, stock, cost) {
    let best = 0;
    const hiBound = budget + Math.max(...stock) + 2;
    for (let i = 0; i < k; i++) {
        const comp = composition[i];
        const feasible = (x) => {
            let total = 0;
            for (let j = 0; j < n; j++) {
                const need = comp[j] * x - stock[j];
                if (need > 0) {
                    total += need * cost[j];
                    if (total > budget) return false;
                }
            }
            return true;
        };
        let lo = 0, hi = hiBound;
        while (lo < hi) {
            const mid = Math.floor((lo + hi + 1) / 2);
            if (feasible(mid)) lo = mid;
            else hi = mid - 1;
        }
        if (lo > best) best = lo;
    }
    return best;
};
